package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetHeaderReturnsCloneOfHeader() throws Exception {
        String[] header = new String[]{"col1", "col2", "col3"};
        CSVFormat format = createCSVFormatWithHeader(header);
        String[] result = format.getHeader();
        assertNotNull(result);
        assertArrayEquals(header, result);
        assertNotSame(header, result);
    }

    @Test
    void testGetHeaderReturnsNullWhenHeaderIsNull() throws Exception {
        CSVFormat format = createCSVFormatWithHeader(null);
        assertNull(format.getHeader());
    }

    private CSVFormat createCSVFormatWithHeader(String[] header) throws Exception {
        // Using the DEFAULT instance and replacing the private final header field via reflection
        CSVFormat format = CSVFormat.DEFAULT;
        Field headerField = CSVFormat.class.getDeclaredField("header");
        headerField.setAccessible(true);

        // Remove final modifier to allow modification
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(headerField, headerField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        headerField.set(format, header);
        return format;
    }
}
